import{_ as a,o,c as d,ag as r}from"./chunks/framework.DXGyWiRo.js";const b=JSON.parse('{"title":"1.1 集合的概念","description":"","frontmatter":{},"headers":[],"relativePath":"notes/gaozhong/gaoyi/chapter01-sets/1-1-集合的概念.md","filePath":"notes/gaozhong/gaoyi/chapter01-sets/1-1-集合的概念.md"}'),e={name:"notes/gaozhong/gaoyi/chapter01-sets/1-1-集合的概念.md"};function s(l,t,i,n,h,$){return o(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="_1-1-集合的概念" tabindex="-1">1.1 集合的概念 <a class="header-anchor" href="#_1-1-集合的概念" aria-label="Permalink to &quot;1.1 集合的概念&quot;">​</a></h1><h2 id="一、集合的定义" tabindex="-1">一、集合的定义 <a class="header-anchor" href="#一、集合的定义" aria-label="Permalink to &quot;一、集合的定义&quot;">​</a></h2><p><strong>集合</strong>：把一些能够确定的、不同的对象汇集在一起，形成的整体。</p><ul><li>这些对象称为集合的<strong>元素</strong></li><li>集合通常用大写字母 $A, B, C, \\cdots$ 表示</li><li>元素通常用小写字母 $a, b, c, \\cdots$ 表示</li></ul><h2 id="二、元素与集合的关系" tabindex="-1">二、元素与集合的关系 <a class="header-anchor" href="#二、元素与集合的关系" aria-label="Permalink to &quot;二、元素与集合的关系&quot;">​</a></h2><p>对于元素 $a$ 与集合 $A$：</p><ul><li>若 $a$ 在集合 $A$ 中，称 $a$ <strong>属于</strong> $A$，记作 $a \\in A$</li><li>若 $a$ 不在集合 $A$ 中，称 $a$ <strong>不属于</strong> $A$，记作 $a \\notin A$</li></ul><div class="tip custom-block"><p class="custom-block-title">记忆口诀</p><p>属于 / 不属于，看元素是否在集合&quot;里面&quot;。</p></div><h2 id="三、集合的特性" tabindex="-1">三、集合的特性 <a class="header-anchor" href="#三、集合的特性" aria-label="Permalink to &quot;三、集合的特性&quot;">​</a></h2><table tabindex="0"><thead><tr><th>特性</th><th>说明</th></tr></thead><tbody><tr><td><strong>确定性</strong></td><td>任意元素是否属于集合是明确无误的</td></tr><tr><td><strong>互异性</strong></td><td>集合中的元素互不重复</td></tr><tr><td><strong>无序性</strong></td><td>集合中的元素没有顺序之分</td></tr></tbody></table><h2 id="四、常用数集" tabindex="-1">四、常用数集 <a class="header-anchor" href="#四、常用数集" aria-label="Permalink to &quot;四、常用数集&quot;">​</a></h2><table tabindex="0"><thead><tr><th>符号</th><th>集合名称</th><th>包含的数</th></tr></thead><tbody><tr><td>$\\mathbb{N}$</td><td>自然数集</td><td>$0, 1, 2, 3, \\cdots$</td></tr><tr><td>$\\mathbb{N}^*$ 或 $\\mathbb{N}_+$</td><td>正整数集</td><td>$1, 2, 3, \\cdots$</td></tr><tr><td>$\\mathbb{Z}$</td><td>整数集</td><td>$\\cdots, -2, -1, 0, 1, 2, \\cdots$</td></tr><tr><td>$\\mathbb{Q}$</td><td>有理数集</td><td>整数、分数（有限小数或循环小数）</td></tr><tr><td>$\\mathbb{R}$</td><td>实数集</td><td>有理数 + 无理数</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">注意</p><p>沪教版的自然数集 $\\mathbb{N}$ 通常包含 $0$，需留意题目要求。</p></div><h2 id="五、例题" tabindex="-1">五、例题 <a class="header-anchor" href="#五、例题" aria-label="Permalink to &quot;五、例题&quot;">​</a></h2><details class="details custom-block"><summary>点击查看例题</summary><p><strong>例1：</strong> 判断下列对象能否组成集合，并说明理由。</p><p>（1）大于 5 的整数；　（2）世界上最高的山；　（3）的好朋友。</p><p><strong>解析：</strong></p><ul><li>（1）可以组成集合 —— 每个整数是否大于 5 是确定的</li><li>（2）可以组成集合 —— 世界上最高的山是确定的（珠穆朗玛峰）</li><li>（3）不能组成集合 —— &quot;漂亮&quot;没有确定的标准，因人而异</li></ul></details>',15)])])}const u=a(e,[["render",s]]);export{b as __pageData,u as default};
